# site-wide patches applied to every Python interpreter startup.
#
# The iOS PyTorch build was compiled with USE_NUMPY=0 (rationale:
# binary size + ABI lock against bundled numpy). That makes
# `torch.from_numpy(arr)` and `tensor.numpy()` raise:
#
#     RuntimeError: PyTorch was compiled without NumPy support
#
# Both are heavily used inside transformers, diffusers, common
# training scripts, and probably every user notebook. Re-enabling
# them properly requires a PyTorch rebuild — out of scope for the
# bundled environment. We can install pure-Python equivalents that
# use the buffer-protocol path (`torch.frombuffer` / explicit byte
# copies), which give equivalent semantics for the call sites that
# actually matter.
#
# Caveats:
#   • The patched `from_numpy` does NOT share memory with the
#     numpy array — it copies once. Original behavior was zero-copy
#     in some paths; this is slightly slower but always correct.
#   • The patched `tensor.numpy()` likewise copies the storage.
#   • Both are no-ops if torch's native implementation already works
#     (i.e. if someone rebuilds torch with USE_NUMPY=1, we step aside).

import sys


def _install_numpy_bridge_shim() -> None:
    try:
        import torch
    except ImportError:
        return     # torch not installed — nothing to patch

    # Probe: does the native from_numpy work? If yes, don't patch.
    try:
        import numpy as np
        torch.from_numpy(np.array([1.0]))
        return     # native works — no shim needed
    except Exception:
        pass

    try:
        import numpy as np
    except ImportError:
        return     # no numpy on this build — nothing to bridge

    # ---- numpy → torch ------------------------------------------------
    _NP_TO_TORCH = {
        np.dtype("float32"): torch.float32,
        np.dtype("float16"): torch.float16,
        np.dtype("float64"): torch.float64,
        np.dtype("int8"):    torch.int8,
        np.dtype("uint8"):   torch.uint8,
        np.dtype("int16"):   torch.int16,
        np.dtype("int32"):   torch.int32,
        np.dtype("int64"):   torch.int64,
        np.dtype("bool"):    torch.bool,
    }

    def _from_numpy(arr):
        """Drop-in replacement for torch.from_numpy when torch was
        built with USE_NUMPY=0. Constructs a tensor by copying the
        numpy array's bytes through torch.frombuffer."""
        if not isinstance(arr, np.ndarray):
            raise TypeError(
                f"expected numpy.ndarray, got {type(arr).__name__}")
        np_dt = arr.dtype
        torch_dt = _NP_TO_TORCH.get(np_dt)
        if torch_dt is None:
            # Unsigned widths > 8: torch lacks native equivalents.
            # Cast through signed of same byte-width.
            if np_dt == np.uint16:
                arr = arr.astype(np.int32, copy=False)
                torch_dt = torch.int32
            elif np_dt == np.uint32:
                arr = arr.astype(np.int64, copy=False)
                torch_dt = torch.int64
            elif np_dt == np.uint64:
                arr = arr.astype(np.int64, copy=False)
                torch_dt = torch.int64
            elif np_dt.kind == "c":
                raise TypeError("complex dtypes not supported by torch shim")
            else:
                # Fallback: convert to float32. Loses precision for
                # exotic dtypes but better than crashing.
                arr = arr.astype(np.float32, copy=False)
                torch_dt = torch.float32
        contig = np.ascontiguousarray(arr)
        buf = bytearray(contig.tobytes())
        t = torch.frombuffer(buf, dtype=torch_dt).reshape(list(contig.shape))
        return t.clone()      # detach from the temp bytearray's lifetime

    # ---- torch → numpy ------------------------------------------------
    _TORCH_TO_NP = {
        torch.float32: np.dtype("float32"),
        torch.float16: np.dtype("float16"),
        torch.float64: np.dtype("float64"),
        torch.int8:    np.dtype("int8"),
        torch.uint8:   np.dtype("uint8"),
        torch.int16:   np.dtype("int16"),
        torch.int32:   np.dtype("int32"),
        torch.int64:   np.dtype("int64"),
        torch.bool:    np.dtype("bool"),
    }

    def _tensor_to_numpy(self):
        """Drop-in replacement for tensor.numpy()."""
        if self.is_cuda:
            self = self.cpu()
        # Detach from autograd so reading .data is safe.
        t = self.detach().contiguous()
        np_dt = _TORCH_TO_NP.get(t.dtype)
        if np_dt is None:
            # bfloat16 / complex / etc. — bounce via float32.
            t = t.to(torch.float32)
            np_dt = np.dtype("float32")
        # Pull raw bytes via the storage and copy into a new numpy array.
        try:
            stg = t.untyped_storage()
            buf = bytes(stg)[:t.numel() * t.element_size()]
        except AttributeError:
            buf = bytes(t.numpy().tobytes())  # would recurse, but only if storage missing
        return np.frombuffer(buf, dtype=np_dt).copy().reshape(list(t.shape))

    # ---- Install -----------------------------------------------------
    torch.from_numpy = _from_numpy
    # `tensor.numpy()` is a C method — assigning to torch.Tensor.numpy
    # replaces it for all instances. Python tolerates this for Tensor
    # because it's defined as a regular method on the class object.
    try:
        torch.Tensor.numpy = _tensor_to_numpy
    except Exception:
        pass    # some torch versions lock the slot; from_numpy alone is the bigger win

    sys.modules.setdefault("__codebench_numpy_shim_installed__", True)


def _install_metal_matmul_bridge() -> None:
    """Route large 2-D float32 matmuls through the iPad GPU via the
    Swift @_cdecl Metal bridge. No-op outside CodeBench (where the
    Swift symbols aren't linked into the running executable).

    Lives here in sitecustomize so any python script — user notebook,
    transformers, hand-rolled training loop — picks it up before
    importing torch."""
    try:
        import _torch_metal_bridge
    except ImportError:
        return     # bridge module not bundled in this build
    _torch_metal_bridge.install(verbose=False)


# ────────────────────────────────────────────────────────────────────
# Auto-enable iOS background-time extension
# ────────────────────────────────────────────────────────────────────
# The goal: a HuggingFace / PyTorch training script written for
# macOS/Windows runs unchanged on iPad. The user shouldn't have to
# `import _cb_background; bg.enable()` — the runtime does it.
#
# `cb_bg_acquire` is reachable only inside CodeBench (where the Swift
# symbols are linked). Elsewhere it's a no-op, so this is safe to
# run unconditionally — scripts on Mac/Linux see exactly the same
# behavior as on iPad's foreground state (no extension granted, but
# also no breakage).
#
# Disable with `CODEBENCH_AUTO_BACKGROUND=0`.

def _enable_background_extension() -> None:
    import os
    if os.environ.get("CODEBENCH_AUTO_BACKGROUND", "1").lower() in (
            "0", "false", "no", "off"):
        return
    try:
        import _cb_background
    except ImportError:
        return
    _cb_background.enable()


# ────────────────────────────────────────────────────────────────────
# Auto-patch transformers for iPad-friendly defaults
# ────────────────────────────────────────────────────────────────────
# HuggingFace `Trainer` already has periodic checkpointing — but its
# defaults (save_steps=500, no save_total_limit) eat disk and don't
# checkpoint often enough for iPad's "user might background the app
# any second" reality.
#
# Patch `TrainingArguments` to inject sensible defaults (save_steps=
# 100, save_total_limit=3) UNLESS the user already specified them.
# Patch `Trainer.train()` to auto-detect & resume from the last
# checkpoint, so a script that crashed mid-run picks up where it
# left off the next time it's invoked — no `resume_from_checkpoint=`
# argument required.
#
# We install this via an import hook (lazy) so importing this file
# doesn't drag transformers in eagerly — sitecustomize runs on EVERY
# Python startup, including `python -c "..."` one-liners.
#
# Disable with `CODEBENCH_AUTO_CHECKPOINT=0`.

def _apply_transformers_defaults(transformers_mod) -> None:
    """Called once, right after `transformers` finishes loading."""
    import os
    try:
        TA = transformers_mod.TrainingArguments
    except AttributeError:
        return
    orig_ta_init = TA.__init__

    def _patched_ta_init(self, *args, **kwargs):
        # setdefault: only inject if user didn't pass these explicitly.
        kwargs.setdefault("save_steps", 100)
        kwargs.setdefault("save_total_limit", 3)
        orig_ta_init(self, *args, **kwargs)
    TA.__init__ = _patched_ta_init

    try:
        Trainer = transformers_mod.Trainer
    except AttributeError:
        return
    orig_train = Trainer.train

    def _patched_train(self, resume_from_checkpoint=None, *args, **kwargs):
        if resume_from_checkpoint is None and getattr(self, "args", None):
            d = getattr(self.args, "output_dir", None)
            if d and os.path.isdir(d):
                try:
                    for entry in os.listdir(d):
                        if (entry.startswith("checkpoint-")
                                and os.path.isdir(os.path.join(d, entry))):
                            resume_from_checkpoint = True
                            break
                except OSError:
                    pass
        return orig_train(self, resume_from_checkpoint, *args, **kwargs)
    Trainer.train = _patched_train


def _install_transformers_import_hook() -> None:
    """Install a sys.meta_path finder that patches transformers on
    first import. Doesn't load transformers itself — so trivial
    Python invocations don't pay the 3-5s transformers import cost."""
    import os
    if os.environ.get("CODEBENCH_AUTO_CHECKPOINT", "1").lower() in (
            "0", "false", "no", "off"):
        return

    import importlib.abc
    import importlib.util

    class _TransformersAutoPatcher(importlib.abc.MetaPathFinder,
                                   importlib.abc.Loader):
        _fired = False
        _wrapped_loader = None

        def find_spec(self, fullname, path=None, target=None):
            if fullname != "transformers" or self._fired:
                return None
            # Temporarily remove self so importlib.util.find_spec
            # doesn't recurse into our own finder.
            try:
                sys.meta_path.remove(self)
            except ValueError:
                return None
            real_spec = importlib.util.find_spec(fullname)
            # Don't re-insert — we fire only once.
            self._fired = True
            if real_spec is None or real_spec.loader is None:
                return None
            self._wrapped_loader = real_spec.loader

            # Use spec_from_file_location, NOT spec_from_loader.
            # spec_from_loader doesn't flip `_set_fileattr = True` on
            # the resulting ModuleSpec, so importlib's
            # `_init_module_attrs` skips setting `module.__file__`.
            # transformers' __init__.py later does
            # `globals()["__file__"]` (HF lazy-import scaffolding) and
            # crashes with KeyError if __file__ isn't set.
            # spec_from_file_location explicitly sets _set_fileattr.
            new_spec = importlib.util.spec_from_file_location(
                fullname,
                real_spec.origin,
                loader=self,
                submodule_search_locations=getattr(
                    real_spec, "submodule_search_locations", None),
            )
            return new_spec

        def create_module(self, spec):
            if hasattr(self._wrapped_loader, "create_module"):
                return self._wrapped_loader.create_module(spec)
            return None

        def exec_module(self, module):
            # Belt-and-braces: ensure __file__ is set on the module
            # before running its code. importlib should've done this
            # already via our spec's origin, but if for some reason
            # it didn't (e.g. an unusual loader path), fall back to
            # the spec's origin manually.
            if not hasattr(module, "__file__") and getattr(
                    module, "__spec__", None) is not None:
                origin = getattr(module.__spec__, "origin", None)
                if origin and not origin.startswith("<"):
                    module.__file__ = origin
            self._wrapped_loader.exec_module(module)
            try:
                _apply_transformers_defaults(module)
            except Exception as e:
                print(f"[sitecustomize] transformers defaults patch "
                      f"failed: {e}", file=sys.stderr)

    sys.meta_path.insert(0, _TransformersAutoPatcher())


# ────────────────────────────────────────────────────────────────────
# Run all installers, guarded so a failure in one doesn't break startup
# ────────────────────────────────────────────────────────────────────

try:
    _install_numpy_bridge_shim()
except Exception as e:
    import sys as _sys
    print(f"[sitecustomize] numpy/torch bridge shim failed: {e}", file=_sys.stderr)

try:
    _install_metal_matmul_bridge()
except Exception as e:
    import sys as _sys
    print(f"[sitecustomize] metal matmul bridge failed: {e}", file=_sys.stderr)

try:
    _enable_background_extension()
except Exception as e:
    import sys as _sys
    print(f"[sitecustomize] background extension failed: {e}", file=_sys.stderr)

try:
    _install_transformers_import_hook()
except Exception as e:
    import sys as _sys
    print(f"[sitecustomize] transformers import hook failed: {e}", file=_sys.stderr)
